// src/modules/comments/service.js
const { randomUUID } = require('node:crypto');
const tasksService = require('../tasks/service');
const commentsStore = {};

async function createComment(projectId, taskId, message) {
  const task = await tasksService.getCommentsForTask(projectId, taskId);
  if (!task) return null;
  const commentId = randomUUID();
  const comment = { id: commentId, message };
  commentsStore[taskId] = [...(commentsStore[taskId] || []), comment];
  return comment;
}

module.exports = {
  createComment,
};

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');
const tasksStore = {};

async function getAllTasks(projectId) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) return null;
  return tasksStore[projectId] || [];
}

async function getCommentsForTask(projectId, taskId) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) return null;
  const task = tasksStore[projectId]?.find(t => t.id === taskId);
  if (!task) return null;
  return task.comments || [];
}

async function createTask(projectId, title, description) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) return null;
  const taskId = randomUUID();
  const task = { id: taskId, title, description, status: 'todo', comments: [] };
  tasksStore[projectId] = [...(tasksStore[projectId] || []), task];
  return task;
}

async function updateTaskStatus(projectId, taskId, status) {
  const project = await projectsService.getProjectById(projectId);
  if (!project) return null;
  const taskIndex = tasksStore[projectId]?.findIndex(t => t.id === taskId);
  if (taskIndex === -1) return null;
  if (status !== 'todo' && status !== 'done') return null;
  tasksStore[projectId][taskIndex].status = status;
  return tasksStore[projectId][taskIndex];
}

module.exports = {
  getAllTasks,
  getCommentsForTask,
  createTask,
  updateTaskStatus,
};
